using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back, optionally in uppercase.")]
    public static string Echo(
        [Description("The message to echo")] string message,
        [Description("If true, convert to uppercase")] bool uppercase = false)
    {
        return uppercase ? message.ToUpperInvariant() : message;
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { Logging = true, Metrics = true }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(UriTemplate = "config://features", Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns the current feature flag settings.")]
    public static string GetFeatureFlags()
    {
        var flags = new
        {
            EnableCaching = true,
            EnableRateLimiting = false,
            MaxRequestsPerMinute = 60
        };

        return JsonSerializer.Serialize(flags, JsonOptions);
    }
}

